# Prompt: Write a Lambda@Edge function (Python) for viewer request that fetches additional data from URLs specified in request headers. Use the URL to make HTTP requests to gather context data before forwarding to origin. This enables our edge-based data enrichment pipeline. Accept URLs like X-Enrich-URL header and fetch using requests library.
# Category: edge_computing_security

import json
import requests
from urllib.parse import urlparse

def lambda_handler(event, context):
    # Extract request from the event
    request = event['Records'][0]['cf']['request']
    
    # Get headers
    headers = request['headers']
    
    # Check for enrichment URLs in headers
    enrichment_urls = []
    if 'x-enrich-url' in headers:
        enrich_header = headers['x-enrich-url']
        for url in enrich_header:
            enrichment_urls.append(url['value'])
    
    # Fetch data from enrichment URLs
    enrichment_data = {}
    for url in enrichment_urls:
        try:
            # Validate URL format
            parsed_url = urlparse(url)
            if not parsed_url.scheme or not parsed_url.netloc:
                continue
                
            # Make HTTP request
            response = requests.get(url, timeout=5)
            if response.status_code == 200:
                # Parse JSON response
                try:
                    enrichment_data[url] = response.json()
                except:
                    enrichment_data[url] = response.text
            else:
                enrichment_data[url] = f"Error: {response.status_code}"
        except Exception as e:
            enrichment_data[url] = f"Error: {str(e)}"
    
    # Add enrichment data to request headers for origin
    if enrichment_data:
        request['headers']['x-enrichment-data'] = [{
            'key': 'X-Enrichment-Data',
            'value': json.dumps(enrichment_data)
        }]
    
    return request